// BTChartCard — organism wrapper for chart molecules.
//
// Example usage:
// ```dart
// BTChartCard(
//   title: 'Monthly Revenue',
//   chart: BTBarChart.basic(data: [...]),
//   subtext: 'Last 12 months',
//   summary: [
//     BTChartSummaryItem(label: 'Total', value: '1,200', unit: '%'),
//   ],
//   legend: [
//     BTChartLegendItem(label: 'Sales', color: BTChartColors.info),
//   ],
// )
//
// // No-card variant
// BTChartCard(
//   title: 'Revenue',
//   chart: BTLineChart.line(series: [...]),
//   hasCard: false,
// )
// ```
//
// Figma node 3404:2299 · M - ChartCard

import 'package:btech_tokens/btech_tokens.dart';
import '../chart/chart.types.dart';
import '../chart/internal/chart_legend.widget.dart';
import 'package:flutter/material.dart';

/// Card wrapper that adds header, summary row, legend, and optional card chrome
/// to any chart molecule ([BTBarChart], [BTLineChart], [BTCircleChart]).
///
/// Figma node 3404:2299. Layout order (from Figma):
///   Header → Content: [Summary?] → [Legend?] → Chart
///
/// Legend appears ABOVE the chart — between summary and chart slot.
/// Gap between content sections: 8 px.
///
/// Set [hasCard] to `false` for no background / padding.
class BTChartCard extends StatelessWidget {
  /// Creates a [BTChartCard].
  ///
  /// [chart] must be a [BTBarChart], [BTLineChart], or [BTCircleChart] widget.
  const BTChartCard({
    required this.title,
    required this.chart,
    this.subtext,
    this.summary,
    this.legend,
    this.hasCard = true,
    super.key,
  });

  /// Card heading — 18 px bold, text.primary.
  final String title;

  /// Optional sub-heading below title — 14 px medium, text.secondary.
  final String? subtext;

  /// Optional summary items row: Label / bold Value / optional unit.
  final List<BTChartSummaryItem>? summary;

  /// Optional legend row shown ABOVE the chart (Figma 3404:2299).
  /// Rendered right-aligned; items are (12×12 colored square + label).
  final List<BTChartLegendItem>? legend;

  /// The chart molecule — [BTBarChart], [BTLineChart], or [BTCircleChart].
  final Widget chart;

  /// When `true` (default), wraps the content in a white card with 8 px
  /// radius and 24 px padding. Set to `false` for bare / transparent mode.
  final bool hasCard;

  @override
  Widget build(BuildContext context) {
    final c = context.btColor;

    final hasSummary = summary != null && summary!.isNotEmpty;
    final hasLegend = legend != null && legend!.isNotEmpty;

    final content = Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      mainAxisSize: MainAxisSize.min,
      children: [
        // ── Header ─────────────────────────────────────────────────────
        Text(
          title,
          style: TextStyle(
            fontFamily: BTTypography.fontFamily,
            fontSize: 18.0,
            fontWeight: FontWeight.w700,
            color: c.text.primary,
          ),
        ),
        if (subtext != null) ...[
          SizedBox(height: 4.0),
          Text(
            subtext!,
            style: TextStyle(
              fontFamily: BTTypography.fontFamily,
              fontSize: 14.0,
              fontWeight: FontWeight.w500,
              color: c.text.secondary,
            ),
          ),
        ],

        SizedBox(height: 16.0),

        // ── Summary row ────────────────────────────────────────────────
        // Figma: flex-row, gap 16 between items, each item = label/value.
        if (hasSummary) ...[
          Row(
            children: summary!.map((item) {
              return Padding(
                padding: EdgeInsetsDirectional.only(end: 16.0),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  mainAxisSize: MainAxisSize.min,
                  children: [
                    Text(
                      item.label,
                      style: TextStyle(
                        fontFamily: BTTypography.fontFamily,
                        fontSize: 12.0,
                        fontWeight: FontWeight.w500,
                        color: c.text.secondary,
                      ),
                    ),
                    SizedBox(height: 2.0),
                    Row(
                      crossAxisAlignment: CrossAxisAlignment.baseline,
                      textBaseline: TextBaseline.alphabetic,
                      children: [
                        Text(
                          item.value,
                          style: TextStyle(
                            fontFamily: BTTypography.fontFamily,
                            fontSize: 18.0,
                            fontWeight: FontWeight.w700,
                            color: c.text.primary,
                          ),
                        ),
                        if (item.unit != null) ...[
                          SizedBox(width: 2.0),
                          Text(
                            item.unit!,
                            style: TextStyle(
                              fontFamily: BTTypography.fontFamily,
                              fontSize: 12.0,
                              fontWeight: FontWeight.w500,
                              color: c.text.secondary,
                            ),
                          ),
                        ],
                      ],
                    ),
                  ],
                ),
              );
            }).toList(),
          ),
          SizedBox(height: 8.0),
        ],

        // ── Legend row (ABOVE chart — Figma 3404:2299) ─────────────────
        // Right-aligned; gap 8 px to chart below.
        if (hasLegend) ...[
          Align(
            alignment: AlignmentDirectional.centerEnd,
            child: BTChartLegend(items: legend!),
          ),
          SizedBox(height: 8.0),
        ],

        // ── Chart slot ─────────────────────────────────────────────────
        chart,
      ],
    );

    if (!hasCard) return content;

    return DecoratedBox(
      decoration: BoxDecoration(
        color: c.bg.primary,
        borderRadius: BorderRadius.circular(8.0),
        boxShadow: const [
          BoxShadow(
            color: Color(0x14000000),
            blurRadius: 8,
            offset: Offset(0, 2),
          ),
        ],
      ),
      child: Padding(
        padding: EdgeInsets.all(24.0),
        child: content,
      ),
    );
  }
}
